const express = require('express');
const app = express();
const port = 3000;

app.get('/api/user/:id', (req, res) => {
    const userId = req.params.id;
    
    if(req.user.id === userId) {
        res.status(200).json({
            id: req.user.id,
            name: req.user.name,
            email: req.user.email
        });
    } else {
        res.status(403).send('Forbidden');
    }
});

app.listen(port, () => {
    console.log(`Server running on port ${port}`);
});